  if (objects[index].(property) < pivot.(property))
    left = {@left, objects[index]};
  else
    right = {@right, objects[index]};
  endif
endfor
return {@this:sort_objects_by_property(left, property), pivot, @this:sort_objects_by_property(right, property)};

