    endif
  elseif (typeof(value) == LIST)
    lines = {@lines, string};
    lines = {@lines, tostr($string_utils:space(depth + 1), toliteral(value))};
  else
    lines = {@lines, string};
    lines = {@lines, tostr($string_utils:space(depth + 1), toliteral(value))};
  endif
endfor
return lines;

