":is_prime(INT number) => INT|ERR";
"Return 1 if number is prime, 0 if not prime, or E_TYPE for a non-integer argument.";
{number} = args;
if (typeof(number) != INT)
  return E_TYPE;
elseif (number == 2)
  return 1;
